SELECT * FROM diary
WHERE user_id = #{userId}
AND date BETWEEN STR_TO_DATE(#{startDate},'%Y-%m-%d') AND STR_TO_DATE(#{endDate},'%Y-%m-%d')

    AND mood_key = #{moodKey}


    AND EXISTS (SELECT 1 FROM diary_tag dt WHERE dt.diary_id = diary.diary_id AND dt.tag_id = #{tagId})

ORDER BY date DESC, created_at DESC
LIMIT #{limit} OFFSET #{offset}

SELECT diary_id, user_id, title, date, LEFT(content, 512) AS content, mood_key, content_format, created_at FROM diary WHERE user_id = #{userId} AND date BETWEEN STR_TO_DATE(#{startDate},'%Y-%m-%d') AND STR_TO_DATE(#{endDate},'%Y-%m-%d')
AND mood_key = #{moodKey}
AND EXISTS (SELECT 1 FROM diary_tag dt WHERE dt.diary_id = diary.diary_id AND dt.tag_id = #{tagId})
ORDER BY date DESC, created_at DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM diary
WHERE user_id = #{userId}
AND date BETWEEN STR_TO_DATE(#{startDate},'%Y-%m-%d') AND STR_TO_DATE(#{endDate},'%Y-%m-%d')

    AND mood_key = #{moodKey}


    AND EXISTS (SELECT 1 FROM diary_tag dt WHERE dt.diary_id = diary.diary_id AND dt.tag_id = #{tagId})

SELECT * FROM diary
WHERE user_id = #{userId}
  AND date BETWEEN STR_TO_DATE(#{startDate},'%Y-%m-%d') AND STR_TO_DATE(#{endDate},'%Y-%m-%d') and
  (title LIKE CONCAT('%', #{searchKeyword}, '%') OR content LIKE CONCAT('%', #{searchKeyword}, '%'))

    AND mood_key = #{moodKey}


    AND EXISTS (SELECT 1 FROM diary_tag dt WHERE dt.diary_id = diary.diary_id AND dt.tag_id = #{tagId})

ORDER BY date DESC, created_at DESC
    LIMIT #{limit} OFFSET #{offset}

SELECT diary_id, user_id, title, date, LEFT(content, 512) AS content, mood_key, content_format, created_at FROM diary WHERE user_id = #{userId} AND date BETWEEN STR_TO_DATE(#{startDate},'%Y-%m-%d') AND STR_TO_DATE(#{endDate},'%Y-%m-%d') and (title LIKE CONCAT('%', #{searchKeyword}, '%') OR content LIKE CONCAT('%', #{searchKeyword}, '%'))
AND mood_key = #{moodKey}
AND EXISTS (SELECT 1 FROM diary_tag dt WHERE dt.diary_id = diary.diary_id AND dt.tag_id = #{tagId})
ORDER BY date DESC, created_at DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM diary
WHERE user_id = #{userId}
  AND date BETWEEN STR_TO_DATE(#{startDate},'%Y-%m-%d') AND STR_TO_DATE(#{endDate},'%Y-%m-%d') and
  (title LIKE CONCAT('%', #{searchKeyword}, '%') OR content LIKE CONCAT('%', #{searchKeyword}, '%'))

    AND mood_key = #{moodKey}


    AND EXISTS (SELECT 1 FROM diary_tag dt WHERE dt.diary_id = diary.diary_id AND dt.tag_id = #{tagId})

SELECT diary_id, user_id, title, date, LEFT(content, 512) AS content, mood_key, content_format, created_at FROM diary WHERE user_id = #{userId}
AND date >= #{startDate}
AND date <= #{endDate}
AND mood_key = #{moodKey}
AND EXISTS (SELECT 1 FROM diary_tag dt WHERE dt.diary_id = diary.diary_id AND dt.tag_id = #{tagId})
ORDER BY date DESC, created_at DESC

SELECT * FROM diary
WHERE user_id = #{userId}
  AND date BETWEEN #{startDate} AND #{endDate}
ORDER BY date ASC, created_at ASC

SELECT DATE_FORMAT(d.date, '%Y-%m-%d') AS date,
       COUNT(*) AS count,
       MIN(d.diary_id) AS firstDiaryId,
       SUBSTRING_INDEX(GROUP_CONCAT(d.title ORDER BY d.created_at ASC SEPARATOR '||'), '||', 1) AS firstTitle
FROM diary d
WHERE d.user_id = #{userId}
  AND d.date >= #{startDate}
  AND d.date <= #{endDate}
GROUP BY d.date
ORDER BY d.date ASC
